 613→func TestShellCompletionTarget(t *testing.T) {
 614→	tests := []struct {
 615→		name             string
 616→		shell            string
 617→		createBashProf   bool
 618→		wantShell        string
 619→		wantRCBase       string // basename of rc file
 620→		wantCompletion   string
 621→		wantErrUnsupport bool
 622→	}{
 623→		{
 624→			name:           "zsh",
 625→			shell:          "/bin/zsh",
 626→			wantShell:      "Zsh",
 627→			wantRCBase:     ".zshrc",
 628→			wantCompletion: "autoload -Uz compinit && compinit && source <(entire completion zsh)",
 629→		},
 630→		{
 631→			name:           "bash_no_profile",
 632→			shell:          "/bin/bash",
 633→			wantShell:      "Bash",
 634→			wantRCBase:     ".bashrc",
 635→			wantCompletion: "source <(entire completion bash)",
 636→		},
 637→		{
 638→			name:           "bash_with_profile",
 639→			shell:          "/bin/bash",
 640→			createBashProf: true,
 641→			wantShell:      "Bash",
 642→			wantRCBase:     ".bash_profile",
 643→			wantCompletion: "source <(entire completion bash)",
 644→		},
 645→		{
 646→			name:           "fish",
 647→			shell:          "/usr/bin/fish",
 648→			wantShell:      "Fish",
 649→			wantRCBase:     filepath.Join(".config", "fish", "config.fish"),
 650→			wantCompletion: "entire completion fish | source",
 651→		},
 652→		{
 653→			name:             "empty_shell",
 654→			shell:            "",
 655→			wantErrUnsupport: true,
 656→		},
 657→	}
 658→
 659→	for _, tt := range tests {
 660→		t.Run(tt.name, func(t *testing.T) {
 661→			home := t.TempDir()
 662→			t.Setenv("HOME", home)
 663→			t.Setenv("SHELL", tt.shell)
 664→
 665→			if tt.createBashProf {
 666→				if err := os.WriteFile(filepath.Join(home, ".bash_profile"), []byte(""), 0o644); err != nil {
 667→					t.Fatal(err)
 668→				}
 669→			}
 670→
 671→			shellName, rcFile, completion, err := shellCompletionTarget()
 672→
 673→			if tt.wantErrUnsupport {
 674→				if !errors.Is(err, errUnsupportedShell) {
 675→					t.Fatalf("got err=%v, want errUnsupportedShell", err)
 676→				}
 677→				return
 678→			}
 679→			if err != nil {
 680→				t.Fatalf("unexpected error: %v", err)
 681→			}
 682→			if shellName != tt.wantShell {
 683→				t.Errorf("shellName = %q, want %q", shellName, tt.wantShell)
 684→			}
 685→			wantRC := filepath.Join(home, tt.wantRCBase)
 686→			if rcFile != wantRC {
 687→				t.Errorf("rcFile = %q, want %q", rcFile, wantRC)
 688→			}
 689→			if completion != tt.wantCompletion {
 690→				t.Errorf("completion = %q, want %q", completion, tt.wantCompletion)
 691→			}
 692→		})
 693→	}
 694→}
