 761→			if !strings.Contains(content, tt.completionLine) {
 762→				t.Errorf("rc file missing completion line %q", tt.completionLine)
 763→			}
 764→			if tt.preExisting != "" && !strings.HasPrefix(content, tt.preExisting) {
 765→				t.Errorf("pre-existing content was overwritten")
 766→			}
 767→
 768→			// Verify parent directory permissions.
 769→			info, err := os.Stat(filepath.Dir(rcFile))
 770→			if err != nil {
 771→				t.Fatalf("stat parent dir: %v", err)
 772→			}
 773→			if !info.IsDir() {
